ence", "recoverable": true}], "interaction_mode": "single_turn", "live_result": {"application_boundary": {"downstream_result_set_available": false, "downstream_status": "not_verified", "judge_scope": "parser_condition_semantics_only", "reason": "application adapter probed downstream customer search before judge/attribute and constrained evaluation scope to parser output semantics.", "result_set_verified": false}, "call_status": "succeeded", "case_id": "cs-age-sex-premium-correct-1", "extracted_output": {"empty_result_reason": "", "external_boundary_sources": {"config_paths": {"source_enhanced_rules": "/Users/xiaozijian/WorkSpace/projects/claude_code/verifier-branch/llm_client_search_0513/llm_client_search/src/main/python/config/enhanced_rules_args.yaml", "source_field_definitions": "/Users/xiaozijian/WorkSpace/projects/claude_code/verifier-branch/llm_client_search_0513/llm_client_search/src/main/python/config/field_definitions_args.yaml", "source_field_enums": "/Users/xiaozijian/WorkSpace/projects/claude_code/verifier-branch/llm_client_search_0513/llm_client_search/src/main/python/config/field_enums_args.yaml", "source_value_mappings": "/Users/xiaozijian/WorkSpace/projects/claude_code/verifier-branch/llm_client_search_0513/llm_client_search/src/main/python/config/value_mappings_args.yaml"}}, "is_empty_result": false, "logic": "AND", "matched_level": 4, "matched_patterns": "### 当前时间\n2026-07-01 03:04:12 (Asia/Shanghai)\n### 今天星期\n周三\n\n### 相关字段参考（根据查询内容动态召回）\n\n\n- **searchClientName** | 操作符: MATCH | 值类型: extract | 定义: 表示客户本人完整姓名，不表示家庭成员、被保人、投保人姓名 | 说明: 当查询直接出现完整中文姓名时，必须保留全名原样输出；如\"陈成\"\"李保\"\"张无\"\"金美\"应输出完整姓名，不能截断为\"陈\"\"李\"\"张\"\"金\"，也不能因为名字较少见而省略、跳过或判定为无效。只有明确出现\"姓张\"\"姓李\"这类姓氏表达时，才可只取姓。\n\n  示例: \"叫张三的客户\" → {\"field\": \"searchClientName\", \"operator\": \"MATCH\", \"value\": \"张三\"}\n\n  示例: \"名字是李四的客户\" → {\"field\": \"searchClientName\", \"operator\": \"MATCH\", \"value\": \"李四\"}\n\n  示例: \"陈成\" → {\"field\": \"searchClientName\", \"operator\": \"MATCH\", \